import java.util.HashMap;
import java.util.OptionalLong;

/**
 * LRU cache with 64-bit long keys and values.
 *
 * Implementation: HashMap<Long,Node> + a manually-built doubly linked list.
 * (Not LinkedHashMap.) All ops are O(1) average.
 *
 * Not-found signal: get(long) returns an OptionalLong. A missing key yields
 * OptionalLong.empty(); a present key yields OptionalLong.of(value).
 * (getOrDefault(key, sentinel) is also provided for the hot benchmark path.)
 *
 * Recency: the head sentinel's next is the most-recently-used node; the tail
 * sentinel's prev is the least-recently-used node (the eviction victim).
 */
public final class LRUCache {

    private static final class Node {
        long key;
        long value;
        Node prev;
        Node next;

        Node(long key, long value) {
            this.key = key;
            this.value = value;
        }
    }

    private final int capacity;
    private final HashMap<Long, Node> map;
    private final Node head; // sentinel: head.next == MRU
    private final Node tail; // sentinel: tail.prev == LRU

    public LRUCache(int capacity) {
        if (capacity <= 0) {
            throw new IllegalArgumentException("capacity must be > 0, got " + capacity);
        }
        this.capacity = capacity;
        // Size the map to avoid rehashing during the workload.
        this.map = new HashMap<>(capacity * 2);
        this.head = new Node(0L, 0L);
        this.tail = new Node(0L, 0L);
        this.head.next = this.tail;
        this.tail.prev = this.head;
    }

    /** Unlink a node from the list. */
    private void unlink(Node n) {
        n.prev.next = n.next;
        n.next.prev = n.prev;
    }

    /** Insert a node right after head (make it MRU). */
    private void insertFront(Node n) {
        n.prev = head;
        n.next = head.next;
        head.next.prev = n;
        head.next = n;
    }

    /** Move an existing node to the front (mark MRU). */
    private void moveToFront(Node n) {
        unlink(n);
        insertFront(n);
    }

    /**
     * Return the value for key and mark it MRU, or OptionalLong.empty() if absent.
     */
    public OptionalLong get(long key) {
        Node n = map.get(key);
        if (n == null) {
            return OptionalLong.empty();
        }
        moveToFront(n);
        return OptionalLong.of(n.value);
    }

    /**
     * Hot-path variant for benchmarking: returns the value if present (marking it
     * MRU), otherwise returns the provided sentinel. Avoids OptionalLong boxing.
     */
    public long getOrDefault(long key, long sentinel) {
        Node n = map.get(key);
        if (n == null) {
            return sentinel;
        }
        moveToFront(n);
        return n.value;
    }

    /** Insert or update key->value; mark MRU; evict LRU if a new key overflows. */
    public void put(long key, long value) {
        Node existing = map.get(key);
        if (existing != null) {
            existing.value = value;
            moveToFront(existing);
            return;
        }
        if (map.size() >= capacity) {
            // Evict LRU (tail.prev).
            Node lru = tail.prev;
            unlink(lru);
            map.remove(lru.key);
        }
        Node n = new Node(key, value);
        insertFront(n);
        map.put(key, n);
    }

    /** Current number of entries. */
    public int len() {
        return map.size();
    }
}

import java.util.OptionalLong;

/**
 * Plain main-based test harness (no JUnit). Prints PASS/FAIL per test and
 * exits with status 1 if any test fails.
 */
public final class LRUCacheTest {

    private static int failures = 0;

    private static void check(String name, boolean cond) {
        if (cond) {
            System.out.println("PASS: " + name);
        } else {
            System.out.println("FAIL: " + name);
            failures++;
        }
    }

    // Test 1: put/get basic hit.
    static void test1() {
        LRUCache c = new LRUCache(2);
        c.put(1L, 100L);
        OptionalLong r = c.get(1L);
        check("1 put/get basic hit", r.isPresent() && r.getAsLong() == 100L);
    }

    // Test 2: get on missing key returns not-found.
    static void test2() {
        LRUCache c = new LRUCache(2);
        c.put(1L, 100L);
        OptionalLong r = c.get(999L);
        check("2 missing key returns not-found", r.isEmpty());
    }

    // Test 3: update existing key changes value, no eviction.
    static void test3() {
        LRUCache c = new LRUCache(2);
        c.put(1L, 100L);
        c.put(2L, 200L);
        c.put(1L, 111L); // update, must not evict key 2
        boolean ok = c.len() == 2
                && c.get(1L).orElse(-1) == 111L
                && c.get(2L).orElse(-1) == 200L;
        check("3 update changes value, no eviction", ok);
    }

    // Test 4: exceeding capacity evicts the LRU key.
    static void test4() {
        LRUCache c = new LRUCache(2);
        c.put(1L, 100L);
        c.put(2L, 200L);
        c.put(3L, 300L); // evicts key 1 (LRU)
        boolean ok = c.len() == 2
                && c.get(1L).isEmpty()
                && c.get(2L).orElse(-1) == 200L
                && c.get(3L).orElse(-1) == 300L;
        check("4 exceeding capacity evicts LRU", ok);
    }

    // Test 5: get() refreshes recency (got key survives subsequent eviction).
    static void test5() {
        LRUCache c = new LRUCache(2);
        c.put(1L, 100L);
        c.put(2L, 200L);
        c.get(1L);       // refresh key 1 -> key 2 is now LRU
        c.put(3L, 300L); // evicts key 2
        boolean ok = c.get(1L).orElse(-1) == 100L
                && c.get(2L).isEmpty()
                && c.get(3L).orElse(-1) == 300L;
        check("5 get refreshes recency", ok);
    }

    // Test 6: capacity 1 edge case.
    static void test6() {
        LRUCache c = new LRUCache(1);
        c.put(1L, 100L);
        boolean a = c.get(1L).orElse(-1) == 100L;
        c.put(2L, 200L); // evicts key 1
        boolean ok = a
                && c.len() == 1
                && c.get(1L).isEmpty()
                && c.get(2L).orElse(-1) == 200L;
        check("6 capacity 1 edge case", ok);
    }

    // Test 7: overwrite refreshes recency.
    static void test7() {
        LRUCache c = new LRUCache(2);
        c.put(1L, 100L);
        c.put(2L, 200L);
        c.put(1L, 111L); // overwrite key 1 -> key 2 is now LRU
        c.put(3L, 300L); // evicts key 2
        boolean ok = c.get(1L).orElse(-1) == 111L
                && c.get(2L).isEmpty()
                && c.get(3L).orElse(-1) == 300L;
        check("7 overwrite refreshes recency", ok);
    }

    public static void main(String[] args) {
        test1();
        test2();
        test3();
        test4();
        test5();
        test6();
        test7();
        if (failures > 0) {
            System.out.println("\n" + failures + " test(s) FAILED");
            System.exit(1);
        }
        System.out.println("\nAll 7 tests passed.");
    }
}

/**
 * Exact benchmark per SPEC.md.
 *
 * LCG (Java longs are 64-bit; signed overflow wraps naturally, matching the
 * unsigned wrapping arithmetic the spec requires):
 *     state = 6364136223846793005 * state + 1442695040888963407
 *     key   = (state >>> 33) % KEYSPACE     // unsigned shift
 * For each op: (state & 1) == 0 -> get(key) else put(key, key)
 * Checksum = sum of successful-get values as a long (natural wrap).
 */
public final class Bench {

    static final int CAPACITY = 10_000;
    static final int OPS = 1_000_000;
    static final long KEYSPACE = 20_000L;

    // Returns checksum (sum of successful-get values, wrapping).
    static long runPass(LRUCache cache, long seed) {
        long state = seed;
        long checksum = 0L;
        final long NOT_FOUND = Long.MIN_VALUE; // sentinel outside key/value range used
        for (int i = 0; i < OPS; i++) {
            state = 6364136223846793005L * state + 1442695040888963407L;
            long key = (state >>> 33) % KEYSPACE;
            if ((state & 1L) == 0L) {
                long v = cache.getOrDefault(key, NOT_FOUND);
                if (v != NOT_FOUND) {
                    checksum += v;
                }
            } else {
                cache.put(key, key);
            }
        }
        return checksum;
    }

    public static void main(String[] args) {
        final long seed = 42L;

        // Warmup pass (not timed) — populate + let JIT warm up.
        LRUCache warm = new LRUCache(CAPACITY);
        long warmChecksum = runPass(warm, seed);

        // Timed pass — fresh cache so the workload is identical to warmup.
        LRUCache cache = new LRUCache(CAPACITY);
        long start = System.nanoTime();
        long checksum = runPass(cache, seed);
        long end = System.nanoTime();

        double elapsedSec = (end - start) / 1_000_000_000.0;
        double opsPerSec = OPS / elapsedSec;

        System.out.println("total ops:    " + OPS);
        System.out.printf("elapsed:      %.6f s%n", elapsedSec);
        System.out.printf("ops/sec:      %.0f%n", opsPerSec);
        System.out.println("final size:   " + cache.len());
        System.out.println("checksum:     " + checksum);
        // Sanity: warmup and timed passes must agree.
        if (warmChecksum != checksum) {
            System.out.println("WARNING: warmup checksum (" + warmChecksum
                    + ") != timed checksum (" + checksum + ")");
        }
    }
}
